def test_run_source_refresh_jobs_default_fetcher_ingests_github_secret_scanning_alerts_metadata_only(tmp_path, monkeypatch):
    root = tmp_path / "capy-memory"
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(root))
